#include<bits/stdc++.h>
using namespace std;
int main()
{
    int n,a[100],b[100],c=0;
    cin>>n;
    for(int i=0;i<n;i++){
        cin>>a[i];
        b[i]=2;
    }
    for(int i=0;i<n;i++){
        for(int j=i+1;j<n;j++){
            for(int k=0;k<n;k++){
                if(a[k]==a[i]+a[j]&&b[k]!=1){
                    c++;
                    b[k]=1;
                }
            }
        }
    }
    cout<<c;
    return 0;
}
